image.asymptote:
// 3-D: PreTeXt renders this to an interactive WebGL figure for the web target.
import three;
size(11cm);
currentprojection=orthographic(4.2,3.4,2.6);

triple o=(0,0,0);
triple ai=(2,0,0);
triple bj=(0,3,0);
triple ck=(0,0,6);

// oriented rectangle u x v in the xy-plane
path3 rect=o--ai--(ai+bj)--bj--cycle;
draw(surface(rect), gray(0.7)+opacity(0.55));
draw(rect, black+linewidth(0.5pt));

// faint coordinate axes
draw(o--(3.0,0,0), gray(0.6), Arrow3);
draw(o--(0,4.0,0), gray(0.6), Arrow3);
draw(o--(0,0,6.8), gray(0.6), Arrow3);
label("$x$", (3.0,0,0), 2S);
label("$y$", (0,4.0,0), 2E);
label("$z$", (0,0,6.8), 2W);

// right-angle markers: k is perpendicular to i and to j
real s=0.45;
draw((s,0,0)--(s,0,s)--(0,0,s), black+linewidth(0.4pt));
draw((0,s,0)--(0,s,s)--(0,0,s), black+linewidth(0.4pt));

// the two edge vectors and their cross product
draw(o--ai, blue+linewidth(1.6pt), Arrow3);
draw(o--bj, blue+linewidth(1.6pt), Arrow3);
draw(o--ck, red+linewidth(1.8pt),  Arrow3);

label("$2\mathbf i$", ai, 2S);
label("$3\mathbf j$", bj, 2E);
label("$6\mathbf k=\mathbf u\times\mathbf v$", ck, N+3E);
label("area $=6$", (ai+bj)/3.2, NW);
dot(o);

image.latex-image:
\begin{tikzpicture}[scale=1.0, >=stealth]
    \draw[->, thick] (0,0) -- (2.4,0) node[right] {\(\mathbf i\)};
    \draw[->, thick] (0,0) -- (0,2.4) node[above] {\(\mathbf j\)};
    \draw[->, thick] (0,0) -- (-1.4,-1.4) node[below left] {\(\mathbf k\)};

    \draw[->] (0.75,0.15) arc (10:80:0.8);
    \node at (1.1,0.85) {\(\mathbf i\to\mathbf j\)};

    \node[right] at (2.7,1.4) {\(\mathbf i\times\mathbf j=\mathbf k\)};
    \node[right] at (2.7,0.8) {\(\mathbf j\times\mathbf i=-\mathbf k\)};
\end{tikzpicture}

statement.p:
If a force \mathbf F is applied at position vector \mathbf r from a
pivot point, then the torque about the pivot is
\boxed{\boldsymbol\tau=\mathbf r\times\mathbf F.}
